ps.pstext:
if !IsFeatureImplemented(FEAT_CMPBR) then EndOfDecode(Decode_UNDEF); end;
let datasize : integer{} = 8 << UInt(H);
let t : integer = UInt(Rt);
let m : integer = UInt(Rm);
let offset : bits(64) = SignExtend{}(imm9::'00');
var op : CmpOp;
var unsigned : boolean;

case cc of
    when '000' => op = Cmp_GT; unsigned = FALSE;
    when '001' => op = Cmp_GE; unsigned = FALSE;
    when '010' => op = Cmp_GT; unsigned = TRUE;
    when '011' => op = Cmp_GE; unsigned = TRUE;
    when '110' => op = Cmp_EQ; unsigned = TRUE;
    when '111' => op = Cmp_NE; unsigned = TRUE;
    otherwise => EndOfDecode(Decode_UNDEF);
end;

let operand1 : bits(datasize) = X{}(t);
let operand2 : bits(datasize) = X{}(m);
let branch_conditional : boolean = TRUE;

let value1 : integer = if unsigned then UInt(operand1) else SInt(operand1);
let value2 : integer = if unsigned then UInt(operand2) else SInt(operand2);
var cond : boolean;
case op of
    when Cmp_EQ => cond = value1 == value2;
    when Cmp_NE => cond = value1 != value2;
    when Cmp_GE => cond = value1 >= value2;
    when Cmp_GT => cond = value1 >  value2;
end;

if cond then
    BranchTo{64}(PC64() + offset, BranchType_DIR, branch_conditional);
else
    BranchNotTaken(BranchType_DIR, branch_conditional);
end;
